usage:
// BOSL2 with gears usage:
include <BOSL2/std.scad>
include <BOSL2/gears.scad>

// Basic spur gear:
spur_gear(circ_pitch=5, teeth=20, thickness=8, shaft_diam=5);

// Meshing gears with automatic positioning:
translate([gear_dist(circ_pitch=5, teeth1=20, teeth2=30), 0, 0])
  spur_gear(circ_pitch=5, teeth=30, thickness=8, shaft_diam=5);
spur_gear(circ_pitch=5, teeth=20, thickness=8, shaft_diam=5);
